INSERT INTO learning_content (chapter_id, session_no, session_name, type, priority, content_en, content_ko, example_en, example_ko, qna_q_en, qna_a_en, qna_q_ko, qna_a_ko, audio_path, created_at) VALUES
(1, 1, '예약 확인', 'WORD', 1, 'reservation', '예약', 'I made a reservation for two.', '두 명으로 예약했습니다.', 'What does \'reservation\' mean?', 'It means a booking made in advance.', '\'Reservation\'이 무슨 뜻인가요?', '사전에 미리 해두는 예약을 뜻합니다.', NULL, NOW()),
(1, 1, '예약 확인', 'WORD', 2, 'confirmation', '확인(서)', 'I received my booking confirmation by email.', '이메일로 예약 확인서를 받았습니다.', 'What is a confirmation number?', 'It\'s a unique code to verify your booking.', '확인 번호(confirmation number)란 무엇인가요?', '예약을 증명하는 고유 코드입니다.', NULL, NOW()),
(1, 1, '예약 확인', 'WORD', 3, 'itinerary', '여행 일정표', 'Please check your travel itinerary before departure.', '출발 전 여행 일정표를 확인하세요.', 'What is an itinerary?', 'It\'s a detailed plan of your trip including flights and hotels.', 'Itinerary란 무엇인가요?', '항공편·호텔 등 여행 계획을 상세히 적은 문서입니다.', NULL, NOW()),
(1, 1, '예약 확인', 'EXPRESSION', 2, 'My booking reference number is ___.', '예약 참조 번호는 ___입니다.', 'My booking reference number is ABC123.', '제 예약 참조 번호는 ABC123입니다.', 'What should I say when calling the airline?', 'Say \'My booking reference number is ___.\'', '항공사에 전화할 때 뭐라고 하나요?', '\'저의 예약 참조 번호는 ___입니다.\'라고 말하세요.', NULL, NOW()),
(1, 1, '예약 확인', 'EXPRESSION', 3, 'I\'d like to confirm my reservation.', '예약을 확인하고 싶습니다.', 'I\'d like to confirm my reservation for flight KE081.', 'KE081편 예약을 확인하고 싶습니다.', 'How do you confirm a reservation by phone?', 'Say \'I\'d like to confirm my reservation.\' then give your booking number.', '전화로 예약 확인은 어떻게 하나요?', '\'예약을 확인하고 싶습니다\'라고 하고 예약번호를 알려주세요.', NULL, NOW()),
(1, 1, '예약 확인', 'EXPRESSION', 1, 'Can I get a confirmation email?', '확인 이메일을 받을 수 있을까요?', 'Could you send me a confirmation email for my booking?', '예약 확인 이메일을 보내주실 수 있나요?', 'I didn\'t receive a confirmation email. What should I ask?', 'Ask \'Can I get a confirmation email?\'', '확인 이메일을 못 받았어요. 뭐라고 물어보나요?', '\'확인 이메일을 받을 수 있을까요?\'라고 물어보세요.', NULL, NOW()),
(1, 1, '예약 확인', 'QNA', 3, 'Is my booking confirmed?', '예약이 확정되었나요?', 'Excuse me, is my booking confirmed for tomorrow\'s flight?', '실례합니다, 내일 비행편 예약이 확정되었나요?', 'Is my booking confirmed?', 'Yes, your booking is confirmed. Your seat is 24A.', '예약이 확정되었나요?', '네, 예약이 확정되었습니다. 좌석은 24A입니다.', NULL, NOW()),
(1, 1, '예약 확인', 'QNA', 1, 'What is the check-in deadline?', '체크인 마감 시간이 언제인가요?', 'What is the check-in deadline for my flight?', '제 비행편의 체크인 마감 시간이 언제인가요?', 'What time do I need to check in?', 'The check-in deadline is usually 1 hour before departure.', '체크인은 몇 시까지 해야 하나요?', '보통 출발 1시간 전까지 체크인해야 합니다.', NULL, NOW()),
(1, 1, '예약 확인', 'QNA', 2, 'Can I change my flight date?', '비행 날짜를 변경할 수 있나요?', 'I need to travel earlier. Can I change my flight date?', '더 일찍 가야 해요. 비행 날짜를 바꿀 수 있나요?', 'Can I change my flight date?', 'Yes, but a change fee may apply depending on your ticket type.', '비행 날짜를 변경할 수 있나요?', '네, 하지만 티켓 종류에 따라 변경 수수료가 발생할 수 있습니다.', NULL, NOW()),
(1, 2, '체크인', 'WORD', 1, 'check-in', '체크인', 'The check-in counter opens at 6 AM.', '체크인 카운터는 오전 6시에 열립니다.', 'Where do I check in?', 'You can check in at the counter or online.', '어디서 체크인하나요?', '카운터나 온라인으로 체크인할 수 있습니다.', NULL, NOW()),
(1, 2, '체크인', 'WORD', 2, 'boarding pass', '탑승권', 'Please show your boarding pass at the gate.', '탑승구에서 탑승권을 제시하세요.', 'What is a boarding pass?', 'It\'s the document that allows you to board the plane.', '탑승권이란 무엇인가요?', '비행기에 탑승할 수 있게 해주는 서류입니다.', NULL, NOW()),
(1, 2, '체크인', 'WORD', 3, 'frequent flyer', '마일리지 회원', 'I\'d like to add my frequent flyer number.', '마일리지 회원 번호를 추가하고 싶습니다.', 'What is a frequent flyer program?', 'It\'s a loyalty program where you earn points for flying.', '마일리지 프로그램이란 무엇인가요?', '비행 시 포인트를 적립하는 항공사 멤버십 프로그램입니다.', NULL, NOW()),
(1, 2, '체크인', 'EXPRESSION', 2, 'I\'d like to check in for my flight.', '제 비행편 체크인을 하고 싶습니다.', 'Hello, I\'d like to check in for my flight to New York.', '안녕하세요, 뉴욕행 비행편 체크인을 하고 싶습니다.', 'What do you say at the check-in counter?', 'Say \'I\'d like to check in for my flight.\'', '체크인 카운터에서 뭐라고 하나요?', '\'제 비행편 체크인을 하고 싶습니다.\'라고 말하세요.', NULL, NOW()),
(1, 2, '체크인', 'EXPRESSION', 3, 'Window seat, please.', '창가 좌석으로 주세요.', 'If possible, I\'d like a window seat, please.', '가능하다면 창가 좌석으로 부탁드립니다.', 'How do you request a window seat?', 'Say \'Window seat, please.\' or \'Aisle seat, please.\'', '창가 좌석을 어떻게 요청하나요?', '\'창가 좌석으로 주세요.\' 또는 \'통로 좌석으로 주세요.\'라고 하면 됩니다.', NULL, NOW()),
(1, 2, '체크인', 'EXPRESSION', 1, 'How many bags can I check in?', '수하물을 몇 개까지 부칠 수 있나요?', 'How many bags can I check in with this ticket?', '이 티켓으로 수하물을 몇 개까지 부칠 수 있나요?', 'I have two suitcases. What should I ask?', 'Ask \'How many bags can I check in?\'', '큰 가방이 두 개인데 뭐라고 물어보나요?', '\'수하물을 몇 개까지 부칠 수 있나요?\'라고 물어보세요.', NULL, NOW()),
(1, 2, '체크인', 'QNA', 3, 'Can I upgrade to business class?', '비즈니스 클래스로 업그레이드할 수 있나요?', 'Is it possible to upgrade to business class at check-in?', '체크인 시 비즈니스 클래스로 업그레이드가 가능한가요?', 'Can I upgrade to business class?', 'Sometimes upgrades are available at the counter for an extra fee.', '비즈니스 클래스로 업그레이드할 수 있나요?', '때때로 추가 요금을 내면 카운터에서 업그레이드가 가능합니다.', NULL, NOW()),
(1, 2, '체크인', 'QNA', 1, 'Is my flight on time?', '제 비행편이 정시 출발인가요?', 'Excuse me, is my flight to London on time?', '실례합니다, 런던행 비행편이 정시 출발인가요?', 'Is my flight on time?', 'Yes, your flight is on time. / No, it\'s delayed by 30 minutes.', '제 비행편이 정시 출발인가요?', '네, 정시 출발 예정입니다. / 아니요, 30분 지연됩니다.', NULL, NOW()),
(1, 2, '체크인', 'QNA', 2, 'Can I add my frequent flyer number?', '마일리지 번호를 추가할 수 있나요?', 'Can I add my frequent flyer number to this booking?', '이 예약에 마일리지 번호를 추가할 수 있나요?', 'Can I add my mileage number now?', 'Yes, please provide your frequent flyer number.', '지금 마일리지 번호를 추가할 수 있나요?', '네, 마일리지 회원 번호를 알려주세요.', NULL, NOW()),
(1, 3, '수하물', 'WORD', 1, 'baggage', '수하물', 'How many pieces of baggage can I bring?', '수하물을 몇 개까지 가져갈 수 있나요?', 'What is baggage?', 'Baggage refers to the bags and luggage you travel with.', '수하물이 무엇인가요?', '여행 시 가져가는 가방과 짐을 말합니다.', NULL, NOW()),
(1, 3, '수하물', 'WORD', 2, 'carry-on', '기내 반입 수하물', 'My carry-on fits in the overhead bin.', '제 기내 수하물은 선반에 들어갑니다.', 'What is carry-on baggage?', 'It\'s the small bag you bring onto the plane with you.', '기내 반입 수하물이란 무엇인가요?', '비행기 안으로 직접 가지고 타는 작은 가방입니다.', NULL, NOW()),
(1, 3, '수하물', 'WORD', 3, 'overweight fee', '초과 수하물 요금', 'I had to pay an overweight fee at the airport.', '공항에서 초과 수하물 요금을 내야 했습니다.', 'What is an overweight fee?', 'It\'s a charge when your baggage exceeds the weight limit.', '초과 수하물 요금이란 무엇인가요?', '수하물이 허용 무게를 초과할 때 내는 추가 요금입니다.', NULL, NOW()),
(1, 3, '수하물', 'EXPRESSION', 2, 'I\'d like to check this bag.', '이 가방을 부치고 싶습니다.', 'I\'d like to check this bag, please.', '이 가방을 부쳐 주세요.', 'How do you hand over your luggage at check-in?', 'Say \'I\'d like to check this bag, please.\'', '체크인 시 짐을 어떻게 맡기나요?', '\'이 가방을 부쳐 주세요.\'라고 하면 됩니다.', NULL, NOW()),
(1, 3, '수하물', 'EXPRESSION', 3, 'My luggage is overweight.', '제 짐이 무게 초과입니다.', 'I think my luggage is overweight. What should I do?', '짐이 무게 초과인 것 같아요. 어떻게 하나요?', 'What do you say if your bag is too heavy?', 'Say \'My luggage is overweight. Can I move some items to my carry-on?\'', '가방이 너무 무거우면 뭐라고 하나요?', '\'짐이 무게 초과예요. 일부를 기내 수하물로 옮겨도 될까요?\'라고 하세요.', NULL, NOW()),
(1, 3, '수하물', 'EXPRESSION', 1, 'Where is the baggage claim?', '수하물 찾는 곳이 어디인가요?', 'Excuse me, where is the baggage claim area?', '실례합니다, 수하물 찾는 곳이 어디인가요?', 'Where do I pick up my bags after arrival?', 'Ask \'Where is the baggage claim?\' and follow the signs.', '도착 후 어디서 짐을 찾나요?', '\'수하물 찾는 곳이 어디인가요?\'라고 묻고 안내판을 따라가세요.', NULL, NOW()),
(1, 3, '수하물', 'QNA', 3, 'Is my bag within the weight limit?', '제 가방이 무게 제한 내에 있나요?', 'Excuse me, is my bag within the weight limit?', '실례합니다, 제 가방이 무게 제한 내에 있나요?', 'Is my bag within the weight limit?', 'Yes, it\'s 22 kg, which is within the 23 kg limit.', '가방이 무게 제한 내에 있나요?', '네, 22kg으로 23kg 제한 내에 있습니다.', NULL, NOW()),
(1, 3, '수하물', 'QNA', 1, 'What is the baggage allowance?', '수하물 허용량이 어떻게 되나요?', 'What is the baggage allowance for economy class?', '이코노미석 수하물 허용량이 어떻게 되나요?', 'How much luggage can I bring?', 'Economy class passengers can check one bag up to 23 kg.', '짐을 얼마나 가져갈 수 있나요?', '이코노미 승객은 23kg 이하 짐 1개를 부칠 수 있습니다.', NULL, NOW()),
(1, 3, '수하물', 'QNA', 2, 'My bag is missing.', '제 가방이 없어졌습니다.', 'I\'ve been waiting 30 minutes and my bag hasn\'t arrived.', '30분째 기다리는데 가방이 안 나왔어요.', 'My bag didn\'t arrive. What should I say?', 'Say \'My bag is missing. Can you help me file a report?\'', '가방이 안 나왔을 때 뭐라고 하나요?', '\'가방이 없어졌어요. 분실 신고를 도와주실 수 있나요?\'라고 말하세요.', NULL, NOW()),
(1, 4, '보안검색', 'WORD', 1, 'security checkpoint', '보안 검색대', 'Please proceed to the security checkpoint.', '보안 검색대로 이동하세요.', 'What is a security checkpoint?', 'It\'s the area where your bags are scanned for prohibited items.', '보안 검색대란 무엇인가요?', '반입 금지 물품을 확인하기 위해 가방을 검사하는 곳입니다.', NULL, NOW()),
(1, 4, '보안검색', 'WORD', 2, 'screening', '보안 검색(스크리닝)', 'All passengers must go through screening.', '모든 승객은 보안 검색을 받아야 합니다.', 'What is screening?', 'It\'s the process of checking passengers for dangerous items.', '스크리닝이란 무엇인가요?', '위험 물품 소지 여부를 확인하는 절차입니다.', NULL, NOW()),
(1, 4, '보안검색', 'WORD', 3, 'prohibited item', '반입 금지 물품', 'Liquids over 100ml are prohibited items in carry-on bags.', '100ml 초과 액체류는 기내 반입 금지 물품입니다.', 'What items are prohibited in carry-on bags?', 'Sharp objects, large liquids, and flammable materials are prohibited.', '기내 반입 금지 물품에는 무엇이 있나요?', '날카로운 물체, 대용량 액체류, 인화성 물질은 반입 금지입니다.', NULL, NOW()),
(1, 4, '보안검색', 'EXPRESSION', 2, 'Please place your items in the bin.', '물건들을 바구니에 넣어 주세요.', 'Please place your laptop and liquids in the bin.', '노트북과 액체류를 바구니에 넣어 주세요.', 'What does the security officer tell you to do?', 'They say \'Please place your items in the bin.\'', '보안 요원이 뭐라고 하나요?', '\'물건들을 바구니에 넣어 주세요.\'라고 합니다.', NULL, NOW()),
(1, 4, '보안검색', 'EXPRESSION', 3, 'Do I need to take off my shoes?', '신발을 벗어야 하나요?', 'Do I need to take off my shoes at the security checkpoint?', '보안 검색대에서 신발을 벗어야 하나요?', 'What should I ask about removing shoes at security?', 'Ask \'Do I need to take off my shoes?\'', '보안 검색 시 신발에 대해 뭐라고 물어보나요?', '\'신발을 벗어야 하나요?\'라고 물어보세요.', NULL, NOW()),
(1, 4, '보안검색', 'EXPRESSION', 1, 'Do I need to take out my laptop?', '노트북을 꺼내야 하나요?', 'Do I need to take out my laptop from my bag?', '가방에서 노트북을 꺼내야 하나요?', 'What should I ask about electronics at security?', 'Ask \'Do I need to take out my laptop?\'', '보안 검색 시 전자기기에 대해 뭐라고 물어보나요?', '\'노트북을 꺼내야 하나요?\'라고 물어보세요.', NULL, NOW()),
(1, 4, '보안검색', 'QNA', 3, 'Can I bring this through security?', '이것을 보안 검색대에 가지고 들어갈 수 있나요?', 'Can I bring this water bottle through security?', '이 물병을 보안 검색대에 가지고 들어갈 수 있나요?', 'Can I bring liquids through security?', 'Only liquids under 100ml in a clear plastic bag are allowed.', '액체류를 가지고 들어갈 수 있나요?', '투명 봉투에 담긴 100ml 이하 액체류만 허용됩니다.', NULL, NOW()),
(1, 4, '보안검색', 'QNA', 1, 'Is this item allowed on the plane?', '이 물건을 기내에 가지고 탈 수 있나요?', 'Is this power bank allowed on the plane?', '이 보조 배터리를 기내에 가지고 탈 수 있나요?', 'Can I bring a power bank on board?', 'Yes, but it must be in your carry-on, not checked baggage.', '보조 배터리를 기내에 반입할 수 있나요?', '네, 하지만 위탁 수하물이 아닌 기내 수하물로만 가능합니다.', NULL, NOW()),
(1, 4, '보안검색', 'QNA', 2, 'Why was I selected for additional screening?', '왜 추가 검색 대상으로 선택되었나요?', 'Excuse me, why was I selected for additional screening?', '실례합니다, 왜 추가 검색을 받아야 하나요?', 'What should you ask if you\'re pulled aside at security?', 'Ask \'Why was I selected for additional screening?\' calmly.', '보안 검색에서 별도 안내를 받으면 뭐라고 물어보나요?', '\'왜 추가 검색 대상으로 선택되었나요?\'라고 침착하게 물어보세요.', NULL, NOW()),
(1, 5, '면세점', 'WORD', 1, 'duty-free', '면세(품)', 'This perfume is available at the duty-free shop.', '이 향수는 면세점에서 구입할 수 있습니다.', 'What does duty-free mean?', 'It means you don\'t pay tax on the items you buy.', 'Duty-free란 무슨 뜻인가요?', '구입하는 물품에 세금을 내지 않는다는 의미입니다.', NULL, NOW()),
(1, 5, '면세점', 'WORD', 2, 'duty-free allowance', '면세 한도', 'The duty-free allowance for alcohol is one liter.', '주류 면세 한도는 1리터입니다.', 'What is a duty-free allowance?', 'It\'s the maximum value of goods you can bring in tax-free.', '면세 한도란 무엇인가요?', '세금 없이 반입할 수 있는 물품의 최대 금액입니다.', NULL, NOW()),
(1, 5, '면세점', 'WORD', 3, 'receipt', '영수증', 'Please keep your receipt for customs.', '세관을 위해 영수증을 보관해 주세요.', 'Why do I need to keep my duty-free receipt?', 'You may need to show it at customs upon arrival.', '면세점 영수증을 왜 보관해야 하나요?', '입국 시 세관에서 제시해야 할 수 있기 때문입니다.', NULL, NOW()),
(1, 5, '면세점', 'EXPRESSION', 2, 'Can I pay in Korean won?', '한국 원화로 결제할 수 있나요?', 'Can I pay in Korean won for this item?', '이 물건을 한국 원화로 결제할 수 있나요?', 'How do you ask about paying in Korean currency?', 'Ask \'Can I pay in Korean won?\'', '한국 원화로 결제하고 싶을 때 뭐라고 하나요?', '\'한국 원화로 결제할 수 있나요?\'라고 하세요.', NULL, NOW()),
(1, 5, '면세점', 'EXPRESSION', 3, 'Do you have this in a different size?', '다른 사이즈로 있나요?', 'I like this perfume. Do you have it in a bigger size?', '이 향수가 마음에 드는데, 더 큰 사이즈로 있나요?', 'How do you ask for a different size in a store?', 'Say \'Do you have this in a different size?\'', '다른 사이즈를 요청할 때 뭐라고 하나요?', '\'다른 사이즈로 있나요?\'라고 하면 됩니다.', NULL, NOW()),
(1, 5, '면세점', 'EXPRESSION', 1, 'Is this tax-free?', '이것은 면세인가요?', 'Excuse me, is this item tax-free?', '실례합니다, 이 물건은 면세인가요?', 'How do you confirm an item is duty-free?', 'Ask \'Is this tax-free?\'', '물건이 면세인지 어떻게 확인하나요?', '\'이것은 면세인가요?\'라고 물어보세요.', NULL, NOW()),
(1, 5, '면세점', 'QNA', 3, 'How much is this?', '이것은 얼마인가요?', 'How much is this bottle of whiskey?', '이 위스키 한 병은 얼마인가요?', 'How much is this?', 'It\'s $45, which is 15% off the retail price.', '이것은 얼마인가요?', '45달러입니다. 정가보다 15% 저렴합니다.', NULL, NOW()),
(1, 5, '면세점', 'QNA', 1, 'Do you have any special offers today?', '오늘 특별 할인이 있나요?', 'Do you have any special offers or promotions today?', '오늘 특별 할인이나 프로모션이 있나요?', 'How do you ask about special deals?', 'Ask \'Do you have any special offers today?\'', '할인 혜택을 어떻게 물어보나요?', '\'오늘 특별 할인이 있나요?\'라고 물어보세요.', NULL, NOW()),
(1, 5, '면세점', 'QNA', 2, 'Can I get a refund?', '환불받을 수 있나요?', 'I changed my mind. Can I get a refund on this item?', '마음이 바뀌었어요. 이 물건을 환불받을 수 있나요?', 'Can I get a refund at the duty-free shop?', 'Refunds are usually not available once you\'ve passed security.', '면세점에서 환불이 가능한가요?', '보안 검색대를 통과한 후에는 보통 환불이 불가합니다.', NULL, NOW()),
(1, 6, '탑승', 'WORD', 1, 'boarding', '탑승', 'Boarding will begin in 10 minutes.', '10분 후에 탑승이 시작됩니다.', 'What is boarding?', 'It\'s the process of getting on the plane.', 'Boarding(탑승)이란 무엇인가요?', '비행기에 타는 과정을 말합니다.', NULL, NOW()),
(1, 6, '탑승', 'WORD', 2, 'departure gate', '출발 탑승구', 'Your departure gate has changed to Gate 22.', '출발 탑승구가 22번으로 변경되었습니다.', 'What is a departure gate?', 'It\'s the area in the airport where you board your specific flight.', 'Departure gate(출발 탑승구)란 무엇인가요?', '공항에서 특정 비행편에 탑승하는 장소입니다.', NULL, NOW()),
(1, 6, '탑승', 'WORD', 3, 'flight delay', '비행 지연', 'The flight delay is due to bad weather.', '비행 지연은 악천후 때문입니다.', 'What is a flight delay?', 'It\'s when a flight departs later than the scheduled time.', '비행 지연이란 무엇인가요?', '비행기가 예정 시간보다 늦게 출발하는 것입니다.', NULL, NOW()),
(1, 6, '탑승', 'EXPRESSION', 2, 'Please have your boarding pass ready.', '탑승권을 준비해 주세요.', 'Please have your boarding pass and passport ready.', '탑승권과 여권을 준비해 주세요.', 'What do you need to show at the gate?', 'Show your boarding pass. Staff says \'Please have your boarding pass ready.\'', '탑승구에서 무엇을 제시해야 하나요?', '탑승권을 제시하세요. 직원이 \'탑승권을 준비해 주세요.\'라고 합니다.', NULL, NOW()),
(1, 6, '탑승', 'EXPRESSION', 3, 'Now boarding all passengers.', '지금 전 승객이 탑승하십니다.', 'Attention, now boarding all passengers for flight KE002.', '안내 말씀드립니다. KE002편 전 승객이 탑승하십니다.', 'What announcement means it\'s time to board?', '\'Now boarding all passengers for flight [number].\'', '탑승 시간을 알리는 방송은 무엇인가요?', '\'[항공편] 전 승객이 탑승하십니다.\'라는 안내 방송입니다.', NULL, NOW()),
(1, 6, '탑승', 'EXPRESSION', 1, 'Has the gate changed?', '탑승구가 변경되었나요?', 'Excuse me, has the gate changed for flight UA880?', '실례합니다, UA880편 탑승구가 변경되었나요?', 'How do you ask if the boarding gate has moved?', 'Ask \'Has the gate changed?\'', '탑승구가 바뀌었는지 어떻게 물어보나요?', '\'탑승구가 변경되었나요?\'라고 물어보세요.', NULL, NOW()),
(1, 6, '탑승', 'QNA', 3, 'Am I at the right gate?', '제가 맞는 탑승구에 있나요?', 'Excuse me, am I at the right gate for flight KE001?', '실례합니다, KE001편 탑승구가 맞나요?', 'Am I at the right gate?', 'Yes, this is Gate 12 for flight KE001 to Seoul.', '제가 맞는 탑승구에 있나요?', '네, 여기가 서울행 KE001편 12번 탑승구입니다.', NULL, NOW()),
(1, 6, '탑승', 'QNA', 1, 'Can I board now?', '지금 탑승해도 되나요?', 'My group was just called. Can I board now?', '제 그룹이 호출되었어요. 지금 탑승해도 되나요?', 'Can I board now?', 'Yes, please have your boarding pass and passport ready.', '지금 탑승해도 되나요?', '네, 탑승권과 여권을 준비해 주세요.', NULL, NOW()),
(1, 6, '탑승', 'QNA', 2, 'Why is the flight delayed?', '왜 비행이 지연되고 있나요?', 'Can you tell me why the flight is delayed?', '왜 비행이 지연되는지 알 수 있을까요?', 'Why is the flight delayed?', 'The delay is due to the late arrival of the incoming aircraft.', '비행이 왜 지연되나요?', '해당 항공기의 연착으로 인해 지연되고 있습니다.', NULL, NOW()),
(1, 7, '기내식', 'WORD', 1, 'meal', '기내 식사', 'Would you like a meal during the flight?', '비행 중 식사를 원하시나요?', 'What kinds of meals are served on the plane?', 'Airlines usually offer chicken, fish, or pasta.', '비행기에서 어떤 식사가 제공되나요?', '보통 닭고기, 생선, 또는 파스타가 제공됩니다.', NULL, NOW()),
(1, 7, '기내식', 'WORD', 2, 'beverage', '음료', 'What beverages would you like with your meal?', '식사와 함께 어떤 음료를 드시겠어요?', 'What is a beverage?', 'A beverage is any kind of drink—water, juice, coffee, or alcohol.', 'Beverage란 무엇인가요?', '물, 주스, 커피, 알코올 등 모든 마실 것을 가리킵니다.', NULL, NOW()),
(1, 7, '기내식', 'WORD', 3, 'dietary restriction', '식이 제한', 'I have a dietary restriction—I\'m allergic to nuts.', '저는 식이 제한이 있어요. 견과류 알레르기가 있습니다.', 'What is a dietary restriction?', 'It means there are foods you cannot eat due to health or beliefs.', '식이 제한이란 무엇인가요?', '건강상 이유나 신념으로 먹을 수 없는 음식이 있다는 뜻입니다.', NULL, NOW()),
(1, 7, '기내식', 'EXPRESSION', 2, 'What are my meal options?', '제 식사 선택지는 무엇인가요?', 'Excuse me, what are my meal options for this flight?', '실례합니다, 이 비행편의 식사 선택지가 무엇인가요?', 'How do you ask what food is available on the plane?', 'Ask \'What are my meal options?\'', '기내에서 먹을 수 있는 음식을 어떻게 물어보나요?', '\'제 식사 선택지는 무엇인가요?\'라고 물어보세요.', NULL, NOW()),
(1, 7, '기내식', 'EXPRESSION', 3, 'I\'ll have the chicken, please.', '닭고기로 주세요.', 'I\'ll have the chicken and a glass of orange juice, please.', '닭고기와 오렌지 주스 한 잔 주세요.', 'How do you choose your meal on the plane?', 'Say \'I\'ll have the chicken, please.\' or your preferred option.', '비행기에서 식사를 어떻게 선택하나요?', '\'닭고기로 주세요.\' 또는 원하는 메뉴를 말하면 됩니다.', NULL, NOW()),
(1, 7, '기내식', 'EXPRESSION', 1, 'Could I have another drink, please?', '음료를 한 잔 더 주실 수 있나요?', 'Could I have another glass of water, please?', '물 한 잔 더 주실 수 있나요?', 'How do you ask for more drinks on the plane?', 'Say \'Could I have another drink, please?\'', '기내에서 음료를 더 달라고 어떻게 하나요?', '\'음료를 한 잔 더 주실 수 있나요?\'라고 하세요.', NULL, NOW()),
(1, 7, '기내식', 'QNA', 3, 'Do you have a vegetarian option?', '채식 메뉴가 있나요?', 'Excuse me, do you have a vegetarian option for this meal?', '실례합니다, 이 식사에 채식 메뉴가 있나요?', 'Do you have a vegetarian option?', 'Yes, we have a vegetarian pasta dish available.', '채식 메뉴가 있나요?', '네, 채식 파스타 요리가 있습니다.', NULL, NOW()),
(1, 7, '기내식', 'QNA', 1, 'When will the meal be served?', '식사는 언제 제공되나요?', 'What time will the meal be served on this flight?', '이 비행편에서 식사는 몇 시에 제공되나요?', 'When is the meal served?', 'The meal will be served about one hour after takeoff.', '식사는 언제 나오나요?', '이륙 후 약 1시간 후에 식사가 제공됩니다.', NULL, NOW()),
(1, 7, '기내식', 'QNA', 2, 'Can I have some extra napkins?', '냅킨을 더 주실 수 있나요?', 'Excuse me, can I have some extra napkins, please?', '실례합니다, 냅킨을 좀 더 주실 수 있나요?', 'How do you ask for more napkins?', 'Say \'Can I have some extra napkins, please?\'', '냅킨을 더 달라고 어떻게 하나요?', '\'냅킨을 좀 더 주실 수 있나요?\'라고 하면 됩니다.', NULL, NOW()),
(1, 8, '좌석 조절', 'WORD', 1, 'recline', '등받이 젖히기', 'May I recline my seat?', '제 좌석 등받이를 젖혀도 될까요?', 'What does \'recline\' mean?', 'To recline means to lean the seatback for more comfort.', '\'Recline\'이란 무슨 뜻인가요?', '좌석 등받이를 뒤로 젖혀 더 편하게 앉는 것을 말합니다.', NULL, NOW()),
(1, 8, '좌석 조절', 'WORD', 2, 'tray table', '접이식 테이블(트레이 테이블)', 'Please return your tray table to its upright position.', '접이식 테이블을 원위치로 되돌려 주세요.', 'What is a tray table?', 'It\'s the small folding table attached to the seat in front of you.', 'Tray table이란 무엇인가요?', '앞 좌석에 붙어 있는 작은 접이식 테이블입니다.', NULL, NOW()),
(1, 8, '좌석 조절', 'WORD', 3, 'overhead bin', '머리 위 짐칸(오버헤드 빈)', 'Please store your carry-on in the overhead bin.', '기내 수하물을 머리 위 짐칸에 보관해 주세요.', 'What is an overhead bin?', 'It\'s the storage compartment above your seat for carry-on bags.', 'Overhead bin이란 무엇인가요?', '좌석 위에 있는 기내 수하물 보관 칸입니다.', NULL, NOW()),
(1, 8, '좌석 조절', 'EXPRESSION', 2, 'May I recline my seat?', '제 좌석 등받이를 젖혀도 될까요?', 'Excuse me, may I recline my seat a little?', '실례합니다, 제 좌석을 조금 젖혀도 될까요?', 'How do you politely ask to recline your seat?', 'Say \'May I recline my seat?\' to the person behind you.', '좌석을 뒤로 젖힐 때 어떻게 정중히 물어보나요?', '뒷자리 분에게 \'제 좌석 등받이를 젖혀도 될까요?\'라고 하세요.', NULL, NOW()),
(1, 8, '좌석 조절', 'EXPRESSION', 3, 'Could you put your seat back up, please?', '좌석을 원위치로 올려 주시겠어요?', 'We\'re about to land. Could you put your seat back up, please?', '곧 착륙합니다. 좌석을 원위치로 올려 주시겠어요?', 'How do you ask someone to raise their seatback?', 'Say \'Could you put your seat back up, please?\'', '앞자리 분에게 좌석을 올려달라고 어떻게 하나요?', '\'좌석을 원위치로 올려 주시겠어요?\'라고 하면 됩니다.', NULL, NOW()),
(1, 8, '좌석 조절', 'EXPRESSION', 1, 'Is this seat taken?', '이 자리 비었나요?', 'Excuse me, is this seat taken?', '실례합니다, 이 자리 비었나요?', 'How do you ask if a seat is occupied?', 'Ask \'Is this seat taken?\'', '자리가 비어 있는지 어떻게 물어보나요?', '\'이 자리 비었나요?\'라고 물어보세요.', NULL, NOW()),
(1, 8, '좌석 조절', 'QNA', 3, 'Can I switch seats with you?', '자리를 바꿔 주실 수 있나요?', 'Excuse me, can I switch seats with you? I\'d like to sit with my family.', '실례합니다, 가족과 함께 앉고 싶어서요. 자리를 바꿔 주실 수 있나요?', 'Can I switch seats?', 'Sure, I don\'t mind. / I\'m sorry, I prefer this seat.', '자리를 바꿔도 될까요?', '물론이죠. / 죄송하지만 저는 이 자리가 좋습니다.', NULL, NOW()),
(1, 8, '좌석 조절', 'QNA', 1, 'How do I adjust my seat?', '좌석을 어떻게 조절하나요?', 'Excuse me, how do I adjust my seat?', '실례합니다, 좌석을 어떻게 조절하나요?', 'How do I recline my seat?', 'Press the button on the side of the armrest to recline.', '좌석은 어떻게 젖히나요?', '팔걸이 옆 버튼을 누르면 좌석이 뒤로 젖혀집니다.', NULL, NOW()),
(1, 8, '좌석 조절', 'QNA', 2, 'Can I use this armrest?', '이 팔걸이를 써도 될까요?', 'Excuse me, can I use this armrest?', '실례합니다, 이 팔걸이를 써도 될까요?', 'How do you politely ask to use the armrest?', 'Say \'Can I use this armrest?\' with a friendly tone.', '팔걸이를 써도 되는지 어떻게 물어보나요?', '\'이 팔걸이를 써도 될까요?\'라고 친근하게 물어보세요.', NULL, NOW()),
(1, 9, '기내 면세', 'WORD', 1, 'in-flight duty-free', '기내 면세', 'The in-flight duty-free service starts after takeoff.', '기내 면세 서비스는 이륙 후 시작됩니다.', 'What is in-flight duty-free?', 'It\'s the tax-free shopping service available during the flight.', '기내 면세란 무엇인가요?', '비행 중에 이용할 수 있는 면세 쇼핑 서비스입니다.', NULL, NOW()),
(1, 9, '기내 면세', 'WORD', 2, 'in-flight catalog', '기내 쇼핑 카탈로그', 'The in-flight catalog is in the seat pocket in front of you.', '기내 쇼핑 카탈로그는 앞 좌석 주머니에 있습니다.', 'Where can I find the in-flight catalog?', 'It\'s in the seat pocket in front of you.', '기내 카탈로그는 어디에 있나요?', '바로 앞 좌석 주머니 안에 있습니다.', NULL, NOW()),
(1, 9, '기내 면세', 'WORD', 3, 'home delivery', '자택 배송', 'Some airlines offer home delivery for in-flight purchases.', '일부 항공사는 기내 구매 물품의 자택 배송 서비스를 제공합니다.', 'Can I get home delivery for in-flight purchases?', 'Some airlines offer home delivery—please check with the crew.', '기내 구매품을 자택 배송받을 수 있나요?', '일부 항공사에서 제공하므로 승무원에게 문의하세요.', NULL, NOW()),
(1, 9, '기내 면세', 'EXPRESSION', 2, 'I\'d like to buy this item.', '이 물건을 구매하고 싶습니다.', 'I\'d like to buy this perfume from the catalog.', '카탈로그에 있는 이 향수를 구매하고 싶습니다.', 'How do you tell the crew you want to purchase something?', 'Say \'I\'d like to buy this item.\' and show the catalog page.', '기내 면세품 구매 의사를 어떻게 전달하나요?', '\'이 물건을 구매하고 싶습니다.\'라고 하고 카탈로그 페이지를 보여주세요.', NULL, NOW()),
(1, 9, '기내 면세', 'EXPRESSION', 3, 'Do you accept credit cards?', '신용카드로 결제할 수 있나요?', 'Do you accept credit cards for duty-free purchases?', '면세품 구매 시 신용카드로 결제할 수 있나요?', 'How do you ask about payment methods on the plane?', 'Ask \'Do you accept credit cards?\'', '기내 결제 수단을 어떻게 물어보나요?', '\'신용카드로 결제할 수 있나요?\'라고 물어보세요.', NULL, NOW()),
(1, 9, '기내 면세', 'EXPRESSION', 1, 'Can I see the duty-free catalog?', '기내 면세 카탈로그를 볼 수 있을까요?', 'Excuse me, can I see the duty-free catalog?', '실례합니다, 기내 면세 카탈로그를 볼 수 있을까요?', 'How do you ask a flight attendant for the catalog?', 'Ask \'Can I see the duty-free catalog?\'', '승무원에게 카탈로그를 어떻게 요청하나요?', '\'기내 면세 카탈로그를 볼 수 있을까요?\'라고 요청하세요.', NULL, NOW()),
(1, 9, '기내 면세', 'QNA', 3, 'Is this item available in-flight?', '이 물건이 기내에서 구매 가능한가요?', 'Is this perfume available for in-flight purchase?', '이 향수를 기내에서 구매할 수 있나요?', 'Is this item available on the plane?', 'Yes, we have it available. Would you like to purchase it?', '이 물건이 기내에서 판매되나요?', '네, 재고가 있습니다. 구매하시겠어요?', NULL, NOW()),
(1, 9, '기내 면세', 'QNA', 1, 'How do I pay for this?', '어떻게 결제하나요?', 'I\'d like this item. How do I pay?', '이 물건을 살게요. 어떻게 결제하나요?', 'How do I pay for the in-flight purchase?', 'You can pay by credit card or cash in major currencies.', '기내 구매는 어떻게 결제하나요?', '신용카드나 주요 통화 현금으로 결제할 수 있습니다.', NULL, NOW()),
(1, 9, '기내 면세', 'QNA', 2, 'Can I get a receipt for this?', '영수증을 받을 수 있나요?', 'Can I get a receipt for this purchase?', '이 구매에 대한 영수증을 받을 수 있나요?', 'How do you ask for a receipt on the plane?', 'Say \'Can I get a receipt for this?\'', '기내에서 영수증을 어떻게 요청하나요?', '\'영수증을 받을 수 있나요?\'라고 요청하면 됩니다.', NULL, NOW()),
(1, 10, '입국 서류', 'WORD', 1, 'customs', '세관', 'Please proceed to customs after collecting your bags.', '수하물을 찾은 후 세관으로 이동하세요.', 'What is customs?', 'It\'s the area where officials check what you\'re bringing into the country.', '세관이란 무엇인가요?', '나라로 반입하는 물품을 검사하는 곳입니다.', NULL, NOW()),
(1, 10, '입국 서류', 'WORD', 2, 'customs declaration form', '세관 신고서', 'Please fill out the customs declaration form before landing.', '착륙 전에 세관 신고서를 작성해 주세요.', 'What is a customs declaration form?', 'It\'s a form listing items you\'re bringing into the country.', '세관 신고서란 무엇인가요?', '해당 국가로 반입하는 물품을 적는 양식입니다.', NULL, NOW()),
(1, 10, '입국 서류', 'WORD', 3, 'immigration officer', '출입국 심사관', 'The immigration officer will check your visa and passport.', '출입국 심사관이 비자와 여권을 확인합니다.', 'What does an immigration officer do?', 'They check your passport and visa to allow entry into the country.', '출입국 심사관은 어떤 일을 하나요?', '여권과 비자를 확인하여 입국을 허가합니다.', NULL, NOW()),
(1, 10, '입국 서류', 'EXPRESSION', 2, 'The purpose of my visit is tourism.', '방문 목적은 관광입니다.', 'The purpose of my visit is tourism. I\'ll stay for 7 days.', '방문 목적은 관광이고 7일간 머물 예정입니다.', 'What do you say about your reason for visiting?', 'Say \'The purpose of my visit is tourism/business.\'', '방문 이유를 어떻게 말하나요?', '\'방문 목적은 관광/사업입니다.\'라고 말하면 됩니다.', NULL, NOW()),
(1, 10, '입국 서류', 'EXPRESSION', 3, 'Do you have anything to declare?', '신고할 물품이 있으신가요?', 'Do you have anything to declare over the allowed limit?', '허용 한도를 초과하는 신고할 물품이 있으신가요?', 'What does the customs officer ask you?', 'They ask \'Do you have anything to declare?\'', '세관원이 무엇을 묻나요?', '\'신고할 물품이 있으신가요?\'라고 묻습니다.', NULL, NOW()),
(1, 10, '입국 서류', 'EXPRESSION', 1, 'I have nothing to declare.', '신고할 것이 없습니다.', 'I have nothing to declare. Here is my customs form.', '신고할 것이 없습니다. 세관 신고서 여기 있습니다.', 'What do you say if you have nothing to declare?', 'Say \'I have nothing to declare.\' and hand over your form.', '신고할 것이 없을 때 뭐라고 하나요?', '\'신고할 것이 없습니다.\'라고 하고 신고서를 제출하세요.', NULL, NOW()),
(1, 10, '입국 서류', 'QNA', 3, 'Where are you staying?', '어디에 머무실 예정인가요?', 'Where are you staying during your visit?', '방문 기간 동안 어디에 머무실 예정인가요?', 'Where are you staying?', 'I\'m staying at the Hilton Hotel in downtown New York.', '어디에 머무실 예정인가요?', '뉴욕 시내 힐튼 호텔에 머물 예정입니다.', NULL, NOW()),
(1, 10, '입국 서류', 'QNA', 1, 'Do you have a return ticket?', '귀국 항공권이 있으신가요?', 'Do you have a return ticket to show?', '보여드릴 귀국 항공권이 있으신가요?', 'Do you have a return ticket?', 'Yes, here is my return ticket to Seoul on March 20th.', '귀국 항공권이 있으신가요?', '네, 3월 20일 서울행 귀국 항공권이 있습니다.', NULL, NOW()),
(1, 10, '입국 서류', 'QNA', 2, 'How long will you be staying?', '얼마나 머무실 예정인가요?', 'How long will you be staying in the country?', '이 나라에 얼마나 머무실 예정인가요?', 'How long will you be staying?', 'I\'ll be staying for 10 days.', '얼마나 머무실 예정인가요?', '10일 동안 머물 예정입니다.', NULL, NOW());
INSERT INTO culture_tip (chapter_id, session_no, tip_ko, tip_en, created_at) VALUES
(1, 1, '예약 확인 시 PNR(예약번호)을 항상 준비하세요. 미국·유럽 항공사는 전화보다 앱·웹 셀프 체크인을 선호합니다.', '', NOW()),
(1, 2, '온라인 체크인은 출발 24~48시간 전부터 가능합니다. 미리 해두면 공항에서 긴 줄을 서지 않아도 됩니다.', '', NOW()),
(1, 3, '위탁 수하물 무게 초과 시 추가 요금이 매우 비쌉니다. 출발 전 항공사별 수하물 규정(무게·크기)을 꼭 확인하세요.', '', NOW()),
(1, 4, '미국 TSA 규정상 액체류는 100ml 이하 용기만 허용됩니다. 투명 지퍼백에 담아 별도로 꺼내 놓으세요.', '', NOW()),
(1, 5, '귀국 시 면세 한도(한국 기준 미화 $800)를 초과하면 세관 신고가 필요합니다. 영수증을 꼭 보관하세요.', '', NOW()),
(1, 6, '미국 항공사는 그룹별 탑승(Group boarding)을 합니다. 탑승권의 그룹 번호를 확인하고 해당 그룹이 호출될 때까지 기다리세요.', '', NOW()),
(1, 7, '채식·할랄·저염식 등 특별식은 탑승 최소 24~48시간 전에 사전 신청해야 합니다. 기내에서는 변경이 거의 불가합니다.', '', NOW()),
(1, 8, '장거리 비행에서 좌석을 젖히기 전 뒷자리 승객에게 양해를 구하는 것이 기본 에티켓입니다. \'May I recline my seat?\'라고 먼저 물어보세요.', '', NOW()),
(1, 9, '기내 면세 판매는 재고가 한정되어 있습니다. 원하는 상품이 있다면 승무원이 카탈로그를 배포할 때 바로 주문하세요.', '', NOW()),
(1, 10, '미국 입국 시 ESTA(전자여행허가)가 필수입니다. 출발 최소 72시간 전에 온라인(esta.cbp.dhs.gov)으로 신청하세요.', '', NOW());
